use anyhow::{Context, Result};
use clap::Parser;
use std::str::FromStr;

mod rustdoc;
mod typescript;

#[derive(Parser)]
#[command(
    name = "truapi-codegen",
    about = "Generate TS client from TrUAPI Rust traits"
)]
struct Cli {
    /// Path to rustdoc JSON file (generated by `cargo +nightly rustdoc -p truapi --output-format json`)
    #[arg(short, long)]
    input: String,

    /// Output directory for generated files
    #[arg(short, long, default_value = "generated")]
    output: String,

    /// TrUAPI protocol version for the generated TypeScript package.
    ///
    /// Accepts `V<N>` or `<N>`, for example `V1`, `V2`, or `2`.
    #[arg(long, default_value = "V2")]
    version: ProtocolVersionArg,

    /// Wire codec version for generated handshake calls.
    #[arg(long, default_value_t = 1)]
    codec_version: u8,

    /// Output directory for generated playground metadata (optional).
    #[arg(long)]
    playground_output: Option<String>,

    /// Output directory for generated explorer registry data (optional).
    #[arg(long)]
    explorer_output: Option<String>,
}

#[derive(Clone, Copy, Debug)]
struct ProtocolVersionArg(u32);

impl ProtocolVersionArg {
    fn number(self) -> u32 {
        self.0
    }
}

impl FromStr for ProtocolVersionArg {
    type Err = String;

    fn from_str(value: &str) -> Result<Self, Self::Err> {
        let number = value.strip_prefix('V').unwrap_or(value);
        if number.is_empty() {
            return Err("version must be written as V<N> or <N>".to_string());
        }
        let number = number
            .parse::<u32>()
            .map_err(|_| "version must be written as V<N> or <N>".to_string())?;
        if number == 0 {
            return Err("version must be at least V1".to_string());
        }
        Ok(Self(number))
    }
}

fn main() -> Result<()> {
    let cli = Cli::parse();
    let json = std::fs::read_to_string(&cli.input)
        .with_context(|| format!("reading rustdoc JSON from {}", cli.input))?;
    let krate = rustdoc::parse(&json).with_context(|| format!("parsing {}", cli.input))?;
    let api = rustdoc::extract_api(&krate)
        .with_context(|| format!("extracting API definition from {}", cli.input))?;
    typescript::generate(&api, &cli.output, cli.version.number(), cli.codec_version)
        .with_context(|| format!("writing TypeScript client to {}", cli.output))?;
    let output = &cli.output;
    println!(
        "Generated TypeScript client for TrUAPI V{} codec {} in {output}",
        cli.version.number(),
        cli.codec_version
    );
    if let Some(path) = &cli.playground_output {
        typescript::generate_playground_services(&api, path, cli.version.number())
            .with_context(|| format!("writing playground metadata to {path}"))?;
        println!("Generated playground metadata in {path}");
    }
    if let Some(path) = &cli.explorer_output {
        typescript::generate_explorer_registry(&api, path, cli.version.number())
            .with_context(|| format!("writing explorer registry to {path}"))?;
        println!("Generated explorer registry in {path}");
    }
    Ok(())
}
